import React, { useEffect, useState } from "react";
import { useNavigate } from "react-router-dom";
import { fetchMyOrders } from "../services/api/foodAPI";

export default function MyOrdersPage() {
  const navigate = useNavigate();
  const [orders, setOrders] = useState([]);
  const [isLoading, setIsLoading] = useState(true);
  const [error, setError] = useState(null);
  const [filterStatus, setFilterStatus] = useState("all");

  useEffect(() => {
    loadOrders();
  }, []);

  const loadOrders = async () => {
    setIsLoading(true);
    setError(null);

    const response = await fetchMyOrders();

    if (response.success) {
      setOrders(response.data || []);
    } else {
      setError(response.error || "Failed to load orders");
    }

    setIsLoading(false);
  };

  // Filter orders by status
  const filteredOrders =
    filterStatus === "all"
      ? orders
      : orders.filter((order) => order.status === filterStatus);

  const getStatusColor = (status) => {
    const colors = {
      pending: "bg-yellow-100 text-yellow-800",
      accepted: "bg-blue-100 text-blue-800",
      in_progress: "bg-purple-100 text-purple-800",
      completed: "bg-green-100 text-green-800",
      rejected: "bg-red-100 text-red-800",
    };
    return colors[status] || "bg-slate-100 text-slate-800";
  };

  const getStatusLabel = (status) => {
    const labels = {
      pending: "Pending",
      accepted: "Accepted",
      in_progress: "Preparing",
      completed: "Completed",
      rejected: "Rejected",
    };
    return labels[status] || status;
  };

  const formatDate = (dateString) => {
    const date = new Date(dateString);
    return date.toLocaleDateString() + " " + date.toLocaleTimeString();
  };

  return (
    <div className="space-y-6">
      {/* Header */}
      <div className="glass-card p-6">
        <div className="flex items-center justify-between">
          <div>
            <h1 className="text-3xl font-bold text-slate-900">🍔 My Orders</h1>
            <p className="text-slate-600 mt-1">Track your food orders</p>
          </div>
          <button
            onClick={() => navigate("/food")}
            className="px-4 py-2 rounded-lg bg-blue-600 text-white font-semibold hover:bg-blue-700 transition"
          >
            + New Order
          </button>
        </div>
      </div>

      {/* Error Message */}
      {error && (
        <div className="p-4 bg-red-100 text-red-700 rounded-lg flex justify-between items-center">
          <span>{error}</span>
          <button
            onClick={() => setError(null)}
            className="text-red-700 hover:text-red-900 font-bold"
          >
            ✕
          </button>
        </div>
      )}

      {/* Filter */}
      <div className="glass-card p-4">
        <div className="flex flex-wrap gap-2">
          <button
            onClick={() => setFilterStatus("all")}
            className={`px-4 py-2 rounded-lg font-semibold transition ${
              filterStatus === "all"
                ? "bg-blue-600 text-white"
                : "bg-slate-100 text-slate-700 hover:bg-slate-200"
            }`}
          >
            All Orders ({orders.length})
          </button>
          <button
            onClick={() => setFilterStatus("pending")}
            className={`px-4 py-2 rounded-lg font-semibold transition ${
              filterStatus === "pending"
                ? "bg-yellow-600 text-white"
                : "bg-slate-100 text-slate-700 hover:bg-slate-200"
            }`}
          >
            Pending ({orders.filter((o) => o.status === "pending").length})
          </button>
          <button
            onClick={() => setFilterStatus("in_progress")}
            className={`px-4 py-2 rounded-lg font-semibold transition ${
              filterStatus === "in_progress"
                ? "bg-purple-600 text-white"
                : "bg-slate-100 text-slate-700 hover:bg-slate-200"
            }`}
          >
            Preparing ({orders.filter((o) => o.status === "in_progress").length})
          </button>
          <button
            onClick={() => setFilterStatus("completed")}
            className={`px-4 py-2 rounded-lg font-semibold transition ${
              filterStatus === "completed"
                ? "bg-green-600 text-white"
                : "bg-slate-100 text-slate-700 hover:bg-slate-200"
            }`}
          >
            Completed ({orders.filter((o) => o.status === "completed").length})
          </button>
        </div>
      </div>

      {/* Loading State */}
      {isLoading && (
        <div className="glass-card p-8 text-center">
          <p className="text-slate-600">Loading orders...</p>
        </div>
      )}

      {/* Orders List */}
      {!isLoading && filteredOrders.length > 0 && (
        <div className="space-y-4">
          {filteredOrders.map((order) => (
            <div key={order.id} className="glass-card p-6 space-y-4">
              {/* Order Header */}
              <div className="flex items-center justify-between">
                <div>
                  <h3 className="font-bold text-slate-900 text-lg">
                    Order #{order.id.slice(0, 8).toUpperCase()}
                  </h3>
                  <p className="text-sm text-slate-600">
                    {order.restaurant.charAt(0).toUpperCase() +
                      order.restaurant.slice(1).replace("-", " ")}
                  </p>
                </div>
                <span
                  className={`px-4 py-2 rounded-lg font-semibold text-sm ${getStatusColor(
                    order.status
                  )}`}
                >
                  {getStatusLabel(order.status)}
                </span>
              </div>

              {/* Order Items */}
              <div className="bg-slate-50 p-4 rounded-lg">
                <p className="text-sm font-semibold text-slate-600 mb-2">
                  Items:
                </p>
                <ul className="space-y-2">
                  {order.items.map((item, idx) => (
                    <li key={idx} className="text-slate-700 text-sm">
                      <div className="flex justify-between">
                        <span>
                          {item.name} <span className="text-slate-500">×{item.quantity}</span>
                        </span>
                        <span className="font-semibold">₹{item.price * item.quantity}</span>
                      </div>
                    </li>
                  ))}
                </ul>
              </div>

              {/* Order Footer */}
              <div className="flex items-center justify-between border-t border-slate-200 pt-4">
                <div>
                  <p className="text-sm text-slate-600">Ordered</p>
                  <p className="text-xs text-slate-500">
                    {formatDate(order.createdAt)}
                  </p>
                </div>
                <div className="text-right">
                  <p className="text-xl font-bold text-blue-600">
                    ₹{order.total}
                  </p>
                  {order.completedAt && order.status === "completed" && (
                    <p className="text-xs text-green-600 font-semibold">
                      ✓ Completed
                    </p>
                  )}
                </div>
              </div>
            </div>
          ))}
        </div>
      )}

      {/* Empty State */}
      {!isLoading && filteredOrders.length === 0 && (
        <div className="glass-card p-12 text-center">
          <p className="text-4xl mb-4">🛒</p>
          <p className="text-slate-600 text-lg">
            {orders.length === 0
              ? "No orders yet. Place your first order!"
              : `No ${filterStatus} orders`}
          </p>
          {orders.length === 0 && (
            <button
              onClick={() => navigate("/food")}
              className="mt-4 px-6 py-2 rounded-lg bg-blue-600 text-white font-semibold hover:bg-blue-700 transition"
            >
              Browse Restaurants
            </button>
          )}
        </div>
      )}

      {/* Stats Summary */}
      {!isLoading && orders.length > 0 && (
        <div className="glass-card p-6 grid grid-cols-2 md:grid-cols-4 gap-4">
          <div className="text-center">
            <p className="text-slate-600 text-sm">Total Orders</p>
            <p className="text-3xl font-bold text-slate-900">{orders.length}</p>
          </div>
          <div className="text-center">
            <p className="text-slate-600 text-sm">Total Spent</p>
            <p className="text-3xl font-bold text-blue-600">
              ₹{orders.reduce((sum, o) => sum + o.total, 0)}
            </p>
          </div>
          <div className="text-center">
            <p className="text-slate-600 text-sm">Active</p>
            <p className="text-3xl font-bold text-purple-600">
              {
                orders.filter(
                  (o) =>
                    o.status !== "completed" &&
                    o.status !== "rejected"
                ).length
              }
            </p>
          </div>
          <div className="text-center">
            <p className="text-slate-600 text-sm">Completed</p>
            <p className="text-3xl font-bold text-green-600">
              {orders.filter((o) => o.status === "completed").length}
            </p>
          </div>
        </div>
      )}
    </div>
  );
}
